import { useState, useContext } from "react";
import { ThemeProvider, ThemeContext } from "./context/ThemeContext";
import Sidebar from "./components/Sidebar";
import TopBar from "./components/TopBar";
import ChatArea from "./components/ChatArea";

export default function App() {
    const [chats, setChats] = useState(() => {
        const first = {
            id: Date.now(),
            title: "New chat",
            messages: []
        };
        return [first];
    });

    const [activeChatId, setActiveChatId] = useState(chats[0].id);

    const activeChat = chats.find(c => c.id === activeChatId);

    // ✅ ALWAYS add new chat at TOP
    const newChat = () => {
        const chat = {
            id: Date.now(),
            title: "New chat",
            messages: []
        };

        setChats(prev => [chat, ...prev]);
        setActiveChatId(chat.id);
    };

    // Rename chat
    const renameChat = (id, newTitle) => {
        setChats(prev =>
            prev.map(chat =>
                chat.id === id ? { ...chat, title: newTitle } : chat
            )
        );
    };

    // Delete chat
    const deleteChat = (id) => {
        setChats(prev => {
            const remaining = prev.filter(chat => chat.id !== id);

            if (remaining.length === 0) {
                const fresh = {
                    id: Date.now(),
                    title: "New chat",
                    messages: []
                };
                setActiveChatId(fresh.id);
                return [fresh];
            }

            if (id === activeChatId) {
                setActiveChatId(remaining[0].id);
            }

            return remaining;
        });
    };

    // ✅ Add user message AND move chat to top
    const addUserMessage = (text) => {
        setChats(prev => {
            const updated = prev.map(chat =>
                chat.id === activeChatId
                    ? {
                        ...chat,
                        title:
                            chat.messages.length === 0
                                ? text.slice(0, 30)
                                : chat.title,
                        messages: [...chat.messages, { role: "user", text }]
                    }
                    : chat
            );

            const current = updated.find(c => c.id === activeChatId);
            const others = updated.filter(c => c.id !== activeChatId);

            return [current, ...others];
        });
    };

    const streamAIResponse = async (text) => {
        // Add empty AI message first
        setChats(prev =>
            prev.map(chat =>
                chat.id === activeChatId
                    ? {
                        ...chat,
                        messages: [...chat.messages, { role: "ai", text: "" }]
                    }
                    : chat
            )
        );

        const res = await fetch("http://127.0.0.1:8000/api/chat", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ message: text })
        });

        const reader = res.body.getReader();
        const decoder = new TextDecoder();

        let accumulatedText = "";

        while (true) {
            const { value, done } = await reader.read();
            if (done) break;

            accumulatedText += decoder.decode(value);

            // ✅ SAFE: accumulatedText is passed, not captured unsafely
            setChats(prev =>
                prev.map(chat =>
                    chat.id === activeChatId
                        ? {
                            ...chat,
                            messages: chat.messages.map((m, i) =>
                                i === chat.messages.length - 1
                                    ? { ...m, text: accumulatedText }
                                    : m
                            )
                        }
                        : chat
                )
            );
        }
    };
    return (
        <ThemeProvider>
            <ThemedAppWrapper>
                <Sidebar
                    chats={chats}
                    activeChatId={activeChatId}
                    onNewChat={newChat}
                    onSelectChat={setActiveChatId}
                    onRenameChat={renameChat}
                    onDeleteChat={deleteChat}
                />

                <div className="main-wrapper">
                    <TopBar />
                    <ChatArea
                        chat={activeChat}
                        onSend={addUserMessage}
                        onStream={streamAIResponse}
                    />
                </div>
            </ThemedAppWrapper>
        </ThemeProvider>
    );
}

function ThemedAppWrapper({ children }) {
    const { theme } = useContext(ThemeContext);
    return <div className={`app ${theme}`}>{children}</div>;
}
